// Validate required fields for all employees
const employees = Array.isArray($input.all()[0].json.body) ? $input.all()[0].json.body : [$input.all()[0].json.body];
const results = [];

const COUNTRY_RULES = {
  ZA: {
    required: ['grossMonthlySalary', 'country'],
    validateTaxId: (id) => /^\d{13}$/.test(id),
    currency: 'ZAR'
  },
  GB: {
    required: ['grossMonthlySalary', 'country'],
    validateTaxId: (id) => /^[A-Z]{2}\d{6}[A-Z]$/.test(id),
    currency: 'GBP'
  },
  US: {
    required: ['grossMonthlySalary', 'country'],
    validateTaxId: (id) => /^\d{3}-\d{2}-\d{4}$/.test(id),
    currency: 'USD'
  }
};

for (const emp of employees) {
  const errors = [];
  const rules = COUNTRY_RULES[emp.country];

  if (!rules) {
    errors.push('Unsupported country: ' + emp.country + '. Supported: ZA, GB, US');
  } else {
    for (const field of rules.required) {
      if (!emp[field]) errors.push('Missing required field: ' + field);
    }
    if (emp.tax_id && !rules.validateTaxId(emp.tax_id)) {
      errors.push('Invalid tax ID format for ' + emp.country);
    }
    if (emp.grossMonthlySalary && emp.grossMonthlySalary <= 0) {
      errors.push('Gross salary must be positive');
    }
  }

  results.push({
    json: {
      ...emp,
      validation: {
        valid: errors.length === 0,
        errors: errors
      }
    }
  });
}

return results;

// South Africa PAYE + UIF + SDL + Medical Credits + Retirement
const emp = $input.first().json;
const gross = emp.grossMonthlySalary;
const age = emp.age || 30;
const retPct = emp.retirementFundPct || 0;

// PAYE Brackets (2025/2026)
const brackets = [
  { min: 0, max: 237100, rate: 0.18, base: 0 },
  { min: 237100, max: 370500, rate: 0.26, base: 42678 },
  { min: 370500, max: 512800, rate: 0.31, base: 77362 },
  { min: 512800, max: 673000, rate: 0.36, base: 121475 },
  { min: 673000, max: 857900, rate: 0.39, base: 179147 },
  { min: 857900, max: 1817000, rate: 0.41, base: 251258 },
  { min: 1817000, max: Infinity, rate: 0.45, base: 644489 },
];

// Retirement deduction
const retMonthly = gross * (retPct / 100);
const retAnnual = retMonthly * 12;
const annualGross = gross * 12;
const retDeductible = Math.min(retAnnual, annualGross * 0.275, 350000);

// Taxable income
const taxable = annualGross - retDeductible;
let annualPAYE = 0;
for (const b of brackets) {
  if (taxable <= b.max) { annualPAYE = b.base + (taxable - b.min) * b.rate; break; }
}

// Rebates
const rebate = age >= 75 ? 29824 : age >= 65 ? 26679 : 17235;
annualPAYE -= rebate;

// Medical credits
let medCredit = 0;
if (emp.medicalAid) {
  medCredit = 364 + (emp.medicalDependents >= 1 ? 364 : 0) + Math.max(0, (emp.medicalDependents || 0) - 1) * 246;
  annualPAYE -= medCredit * 12;
}
annualPAYE = Math.max(0, annualPAYE);

const monthlyPAYE = Math.round(annualPAYE / 12 * 100) / 100;
const uif = Math.round(Math.min(gross, 17712) * 0.01 * 100) / 100;
const sdl = Math.round(gross * 0.01 * 100) / 100;
const retFund = Math.round(retMonthly * 100) / 100;
const totalDed = monthlyPAYE + uif + retFund;

return [{ json: {
  employee_id: emp.employee_id, full_name: emp.full_name,
  country: 'ZA', currency: 'ZAR', payPeriod: new Date().toISOString().slice(0, 7),
  grossSalary: gross,
  deductions: { paye: monthlyPAYE, uif_employee: uif, retirement_fund: retFund, medical_aid_credit: medCredit },
  totalEmployeeDeductions: Math.round(totalDed * 100) / 100,
  netSalary: Math.round((gross - totalDed) * 100) / 100,
  employerContributions: { uif_employer: uif, sdl: sdl },
  totalCostToEmployer: Math.round((gross + uif + sdl) * 100) / 100
}}];

// United Kingdom Income Tax + NI + Student Loan + Pension
const emp = $input.first().json;
const gross = emp.grossMonthlySalary;
const annual = gross * 12;

// Personal allowance (tapers above 100k)
let pa = 12570;
if (annual > 100000) pa = Math.max(0, 12570 - Math.floor((annual - 100000) / 2));
const taxable = Math.max(0, annual - pa);

// Income tax
let tax = 0, rem = taxable;
tax += Math.min(rem, 37700) * 0.20; rem = Math.max(0, rem - 37700);
tax += Math.min(rem, 74870) * 0.40; rem = Math.max(0, rem - 74870);
if (rem > 0) tax += rem * 0.45;

const monthlyTax = Math.round(tax / 12 * 100) / 100;

// Employee NI
let ni = 0;
if (annual > 12570) {
  ni += Math.min(annual - 12570, 50270 - 12570) * 0.08;
  if (annual > 50270) ni += (annual - 50270) * 0.02;
}
const monthlyNI = Math.round(ni / 12 * 100) / 100;

// Employer NI
const empNI = annual > 5000 ? Math.round((annual - 5000) * 0.15 / 12 * 100) / 100 : 0;

// Student loan
const plans = { plan1: 24990, plan2: 27295, plan4: 31395, plan5: 25000, postgrad: 21000 };
const slRate = emp.studentLoanPlan === 'postgrad' ? 0.06 : 0.09;
const slThreshold = plans[emp.studentLoanPlan] || 0;
const monthlySL = emp.studentLoanPlan && annual > slThreshold
  ? Math.round((annual - slThreshold) * slRate / 12 * 100) / 100 : 0;

// Pension
const pensionRate = emp.pensionPct ? emp.pensionPct / 100 : 0.05;
const qualEarnings = Math.max(0, Math.min(annual, 50270) - 6240);
const monthlyPension = Math.round(qualEarnings * pensionRate / 12 * 100) / 100;
const monthlyErPension = Math.round(qualEarnings * 0.03 / 12 * 100) / 100;

const totalDed = monthlyTax + monthlyNI + monthlySL + monthlyPension;

return [{ json: {
  employee_id: emp.employee_id, full_name: emp.full_name,
  country: 'GB', currency: 'GBP', payPeriod: new Date().toISOString().slice(0, 7),
  grossSalary: gross,
  deductions: { income_tax: monthlyTax, national_insurance: monthlyNI, student_loan: monthlySL, pension_employee: monthlyPension },
  totalEmployeeDeductions: Math.round(totalDed * 100) / 100,
  netSalary: Math.round((gross - totalDed) * 100) / 100,
  employerContributions: { national_insurance: empNI, pension_employer: monthlyErPension },
  totalCostToEmployer: Math.round((gross + empNI + monthlyErPension) * 100) / 100
}}];

// United States Federal + State + FICA + 401(k)
const emp = $input.first().json;
const gross = emp.grossMonthlySalary;
const annual = gross * 12;
const filing = emp.filingStatus || 'single';
const state = emp.state || 'TX';

// 401(k)
const k401Pct = emp.fourOhOnekPct || 0;
let k401Limit = 23500;
const age = emp.age || 30;
if (age >= 60 && age <= 63) k401Limit += 11250;
else if (age >= 50) k401Limit += 7500;
const k401Annual = Math.min(annual * (k401Pct / 100), k401Limit);
const preTax = k401Annual;

// Federal tax
const stdDed = filing === 'married_jointly' ? 30000 : 15000;
const fedTaxable = Math.max(0, annual - preTax - stdDed);
const brackets = filing === 'married_jointly'
  ? [{m:0,x:23850,r:0.10,b:0},{m:23850,x:96950,r:0.12,b:2385},{m:96950,x:206700,r:0.22,b:11157},{m:206700,x:394600,r:0.24,b:35303},{m:394600,x:501050,r:0.32,b:80399},{m:501050,x:751600,r:0.35,b:114463},{m:751600,x:Infinity,r:0.37,b:202155.5}]
  : [{m:0,x:11925,r:0.10,b:0},{m:11925,x:48475,r:0.12,b:1192.5},{m:48475,x:103350,r:0.22,b:5578.5},{m:103350,x:197300,r:0.24,b:17651.5},{m:197300,x:250525,r:0.32,b:40199.5},{m:250525,x:626350,r:0.35,b:57231.5},{m:626350,x:Infinity,r:0.37,b:188769.75}];

let fedTax = 0;
for (const b of brackets) {
  if (fedTaxable <= b.x) {
    fedTax = b.m === 0 ? fedTaxable * b.r : b.b + (fedTaxable - b.m) * b.r;
    break;
  }
}
const monthlyFed = Math.round(fedTax / 12 * 100) / 100;

// Social Security
const ssWages = Math.min(annual - preTax, 176100);
const monthlySS = Math.round(ssWages * 0.062 / 12 * 100) / 100;
const monthlyErSS = monthlySS;

// Medicare
let medTax = (annual - preTax) * 0.0145;
if (annual - preTax > 200000) medTax += (annual - preTax - 200000) * 0.009;
const monthlyMed = Math.round(medTax / 12 * 100) / 100;
const monthlyErMed = Math.round((annual - preTax) * 0.0145 / 12 * 100) / 100;

// State tax (simplified)
const states = {
  TX: { brackets: [], sd: 0 }, FL: { brackets: [], sd: 0 }, WA: { brackets: [], sd: 0 },
  CA: { sd: 5540, brackets: [{m:0,x:10412,r:0.01},{m:10412,x:24684,r:0.02},{m:24684,x:38959,r:0.04},{m:38959,x:54081,r:0.06},{m:54081,x:68350,r:0.08},{m:68350,x:349137,r:0.093},{m:349137,x:418961,r:0.103},{m:418961,x:698271,r:0.113},{m:698271,x:Infinity,r:0.133}] },
  NY: { sd: 8000, brackets: [{m:0,x:8500,r:0.04},{m:8500,x:11700,r:0.045},{m:11700,x:13900,r:0.0525},{m:13900,x:80650,r:0.0585},{m:80650,x:215400,r:0.0625},{m:215400,x:1077550,r:0.0685},{m:1077550,x:5000000,r:0.0965},{m:5000000,x:25000000,r:0.103},{m:25000000,x:Infinity,r:0.109}] }
};
const sc = states[state] || states.TX;
let stateTax = 0;
if (sc.brackets.length > 0) {
  const stTaxable = Math.max(0, annual - preTax - sc.sd);
  let prev = 0;
  for (const b of sc.brackets) {
    if (stTaxable <= b.x) { stateTax += (stTaxable - prev) * b.r; break; }
    else { stateTax += (b.x - prev) * b.r; prev = b.x; }
  }
}
const monthlyState = Math.round(stateTax / 12 * 100) / 100;
const monthly401k = Math.round(k401Annual / 12 * 100) / 100;

const totalDed = monthlyFed + monthlySS + monthlyMed + monthlyState + monthly401k;

return [{ json: {
  employee_id: emp.employee_id, full_name: emp.full_name,
  country: 'US', currency: 'USD', payPeriod: new Date().toISOString().slice(0, 7),
  grossSalary: gross,
  deductions: { federal_income_tax: monthlyFed, social_security: monthlySS, medicare: monthlyMed, state_income_tax: monthlyState, '401k': monthly401k },
  totalEmployeeDeductions: Math.round(totalDed * 100) / 100,
  netSalary: Math.round((gross - totalDed) * 100) / 100,
  employerContributions: { social_security: monthlyErSS, medicare: monthlyErMed },
  totalCostToEmployer: Math.round((gross + monthlyErSS + monthlyErMed) * 100) / 100
}}];
